async function main() {
    // Asegura que exista la configuración con el margen base del 30%.
    await prisma.config.upsert({
        where: { id: 1 },
        update: {},
        create: { id: 1, tasaCambio: 40, margenPorcentaje: 30 }
    });

    let creados = 0;
    let actualizados = 0;

    for (const p of productos) {
        const existente = await prisma.product.findUnique({ where: { codigo: p.codigo } });
        if (existente) {
            await prisma.product.update({
                where: { codigo: p.codigo },
                data: {
                    nombre: p.nombre,
                    costoUsd: p.costoUsd,
                    categoria: p.categoria
                }
            });
            actualizados++;
        } else {
            await prisma.product.create({
                data: {
                    codigo: p.codigo,
                    nombre: p.nombre,
                    costoUsd: p.costoUsd,
                    categoria: p.categoria
                }
            });
            creados++;
        }
    }

    console.log(`Importacion completa: ${creados} productos creados, ${actualizados} actualizados.`);
}

main()
    .catch((e) => {
        console.error(e);
        process.exit(1);
    })
    .finally(() => prisma.$disconnect());